// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title AgentIdentityRegistry
 * @notice ERC-8004 identity layer — registers each AI agent with a unique on-chain ID,
 *         wallet address, role, and metadata URI.
 */
contract AgentIdentityRegistry {

    struct AgentRecord {
        uint256 agentId;       // Unique incrementing ID
        address agentWallet;   // Ethereum address the agent signs with
        string  name;          // Human-readable name e.g. "TrendAgent"
        string  role;          // Role e.g. "trend_follower"
        string  metadataURI;   // IPFS/HTTP link to extended metadata JSON
        bool    active;        // Is this agent currently active?
        uint256 registeredAt;  // Unix timestamp of registration
    }

    uint256 public nextAgentId = 1;

    mapping(uint256 => AgentRecord) public agents;
    mapping(address => uint256)     public walletToAgentId;

    event AgentRegistered(uint256 indexed agentId, address wallet, string name);

    /**
     * @notice Register a new agent on-chain.
     * @param _wallet   The agent's signing wallet address
     * @param _name     Human-readable agent name
     * @param _role     Agent role descriptor
     * @param _metadataURI  URI pointing to full metadata JSON
     * @return The newly assigned agent ID
     */
    function registerAgent(
        address _wallet,
        string memory _name,
        string memory _role,
        string memory _metadataURI
    ) external returns (uint256) {
        uint256 id = nextAgentId++;
        agents[id] = AgentRecord(id, _wallet, _name, _role, _metadataURI, true, block.timestamp);
        walletToAgentId[_wallet] = id;
        emit AgentRegistered(id, _wallet, _name);
        return id;
    }

    /**
     * @notice Check if an agent is currently active.
     */
    function isActive(uint256 agentId) external view returns (bool) {
        return agents[agentId].active;
    }
}

contracts/ReputationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title ReputationRegistry
 * @notice Tracks each agent's reputation score, updated after every trade resolution.
 *         Score starts at 50. +5 for correct predictions, -3 for wrong ones.
 *         The meta-agent reads these scores to weight votes.
 */
contract ReputationRegistry {

    struct ReputationRecord {
        uint256 agentId;
        int256  score;          // Can go negative if agent is consistently wrong
        uint256 totalVotes;     // Total votes cast
        uint256 correctVotes;   // How many were correct
        uint256 lastUpdated;    // Unix timestamp of last update
    }

    mapping(uint256 => ReputationRecord) public reputation;

    address public owner;

    event ReputationUpdated(uint256 indexed agentId, int256 newScore);

    constructor() {
        owner = msg.sender;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "Not authorized");
        _;
    }

    /**
     * @notice Initialize an agent's reputation to 50 (starting score).
     * @param agentId  The agent's on-chain ID from the Identity Registry
     */
    function initAgent(uint256 agentId) external onlyOwner {
        reputation[agentId] = ReputationRecord(agentId, 50, 0, 0, block.timestamp);
    }

    /**
     * @notice Update an agent's reputation after a trade resolves.
     * @param agentId     The agent's on-chain ID
     * @param wasCorrect  Whether the agent's vote matched the actual outcome
     */
    function updateReputation(uint256 agentId, bool wasCorrect) external onlyOwner {
        ReputationRecord storage r = reputation[agentId];
        r.totalVotes += 1;
        if (wasCorrect) {
            r.correctVotes += 1;
            r.score += 5;   // +5 for correct prediction
        } else {
            r.score -= 3;   // -3 for wrong prediction
        }
        r.lastUpdated = block.timestamp;
        emit ReputationUpdated(agentId, r.score);
    }

    /**
     * @notice Get an agent's current reputation score.
     */
    function getScore(uint256 agentId) external view returns (int256) {
        return reputation[agentId].score;
    }

    /**
     * @notice Get full reputation record for an agent.
     */
    function getRecord(uint256 agentId) external view returns (
        int256 score, uint256 totalVotes, uint256 correctVotes, uint256 lastUpdated
    ) {
        ReputationRecord storage r = reputation[agentId];
        return (r.score, r.totalVotes, r.correctVotes, r.lastUpdated);
    }
}

contracts/ValidationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/**
 * @title ValidationRegistry
 * @notice Stores cryptographic hashes of validation artifacts on-chain.
 *         Each vote, trade, and risk check produces a signed receipt whose
 *         SHA-256 hash is logged here for permanent auditability.
 *
 *         Artifact types: VOTE, META_DECISION, TRADE_INTENT, TRADE_CONFIRMED,
 *                         RISK_CHECK, REPUTATION_UPDATE, CHECKPOINT
 */
contract ValidationRegistry {

    struct ValidationArtifact {
        uint256 artifactId;
        uint256 agentId;
        string  artifactType;   // e.g. "VOTE", "TRADE_CONFIRMED"
        bytes32 dataHash;       // SHA-256 hash of the full artifact JSON
        uint256 timestamp;
    }

    uint256 public nextArtifactId = 1;

    mapping(uint256 => ValidationArtifact) public artifacts;
    mapping(uint256 => uint256[]) public agentArtifacts;  // agentId => list of artifact IDs

    event ArtifactLogged(uint256 indexed artifactId, uint256 indexed agentId, string artifactType);

    /**
     * @notice Log a validation artifact hash on-chain.
     * @param agentId       The agent that produced this artifact
     * @param artifactType  Category string (VOTE, TRADE_INTENT, etc.)
     * @param dataHash      SHA-256 hash of the complete artifact JSON
     * @return The newly assigned artifact ID
     */
    function logArtifact(
        uint256 agentId,
        string memory artifactType,
        bytes32 dataHash
    ) external returns (uint256) {
        uint256 id = nextArtifactId++;
        artifacts[id] = ValidationArtifact(id, agentId, artifactType, dataHash, block.timestamp);
        agentArtifacts[agentId].push(id);
        emit ArtifactLogged(id, agentId, artifactType);
        return id;
    }

    /**
     * @notice Get the number of artifacts logged by an agent.
     */
    function getArtifactCount(uint256 agentId) external view returns (uint256) {
        return agentArtifacts[agentId].length;
    }
}

